noncompliant:
// Multiple break statements
for (int i = 0; i < 10; i++) {
  if (condition1) {
    break; // First break
  } else if (condition2) {
    break; // Non-compliant - second break
  }
  process(i);
}

// Multiple goto statements
while (running) {
  if (error1) {
    goto cleanup; // First goto
  }
  if (error2) {
    goto cleanup; // Non-compliant - second goto
  }
  doWork();
}

compliant:
// Single exit point
for (int i = 0; i < 10; i++) {
  if (condition1 || condition2) {
    break; // Single break statement
  }
  process(i);
}

// Restructured logic
bool shouldContinue = true;
while (running && shouldContinue) {
  if (error1 || error2) {
    shouldContinue = false;
  } else {
    doWork();
  }
}
